Script.script:
rents = rents or {}
rents.rares = rents.rares or {}
rents.angreal = rents.angreal or {}
RentViewer = RentViewer or {}

-- ============================================================
-- CONFIG
-- ============================================================
RentViewer.windowName     = "RentViewerWindow"
RentViewer.width          = 1200
RentViewer.height         = 750

RentViewer.oddRowColor    = {0, 0, 0}
RentViewer.evenRowColor   = {0, 0, 0}
RentViewer.textColor      = {185, 185, 185}

RentViewer.oddRowColor    = {20, 20, 28}
--RentViewer.evenRowColor   = {30, 30, 42}
--RentViewer.textColor      = {220, 220, 220}

RentViewer.highlightColor = {128, 200, 255}

RentViewer.sort_by = "name"
RentViewer.sort_ascending    = true

local COLUMN_WIDTHS = {
  name     = 19,
  location = 50,
  item     = 50,
  cost     = 12
}
local COLUMN_GAP = 4

-- ============================================================
-- UTILITIES
-- ============================================================
local function getCenteredCoordinates()
  local screenW, screenH = getMainWindowSize()
  local x = math.max(0, math.floor((screenW - RentViewer.width) / 2))
  local y = math.max(0, math.floor((screenH - RentViewer.height) / 2))
  return x, y
end

-- ============================================================
-- DATA
-- ============================================================
function RentViewer:fetch_records()
  local rents_db = db:get_database("rents")
  local records = db:fetch(rents_db.storage)

  for _, rec in ipairs(records) do
    if rec.item == "bank balance" then
      rec.zone = "*Bank"
      rec.location = "*Bank"
    else
      local roomname = getRoomName(rec.room) or ""
      rec.location = f'{rec.zone}: {roomname}'
    end
    rec.coppers = rents:str_to_coppers(rec.cost)
  end
  return records
end

function RentViewer:get_unique_values(field)
  local list = {}
  for _, rec in ipairs(self.records) do
    table.insert(list, rec[field])
  end
  --remove duplicates
  list = table.n_union(list, list)
  table.sort(list)
  return list
end

function RentViewer:get_zones_for_name(name)
  local list = {}
  for _, rec in ipairs(self.records) do
    if name == "All" or rec.name == name then
      table.insert(list, rec.zone)
    end
  end
  list = table.n_union(list, list)
  table.sort(list)
  return list
end

-- ============================================================
-- DROPDOWN WIDGET
-- ============================================================
function RentViewer:create_dropdown(cfg)
  local parent = cfg.parent or self.window
  local optionH = 20 --height for the options labels

  local dropdown = Geyser.Label:new({
    name = f'{cfg.name}.label',
    x = cfg.x, y = cfg.y,
    width = cfg.width, height = cfg.height,
  }, parent)
  dropdown:setStyleSheet([[
    background-color: rgb(30,30,40);
    border: 1px solid rgb(90,90,110);
    color: rgb(220,220,220);
    font-size: 11px;
    padding-left: 4px;
    border-radius: 4px;
  ]])
  dropdown:echo("All")

  dropdown.caret = Geyser.Label:new({
    name = f'{cfg.name}.caret',
    x = "-20px", y = 0, width = "20px", height = "100%",
  }, dropdown)
  dropdown.caret:setStyleSheet([[
    background-color: rgba(0,0,0,0);
    color: rgb(130,130,150);
    font-size: 9px;
  ]])
  dropdown.caret:echo("▼")
  dropdown.caret:setAlignment("center")

  local options = {"All"}
  for _, opt in ipairs(cfg.options or {}) do
    table.insert(options, opt)
  end

  dropdown.list = Geyser.Container:new({
    name = f'{cfg.name}.list',
    x = cfg.x, y = cfg.y + cfg.height,
    width = cfg.width, height = math.min(optionH * #options, 300),
  }, parent)
  dropdown.list:hide()

  for i, val in ipairs(options) do
    local opt = Geyser.Label:new({
      name = f'{cfg.name}.opt_{i}',
      x = 0, y = (i - 1) * optionH,
      width = cfg.width, height = optionH,
    }, dropdown.list)
    opt:setStyleSheet([[
      background-color: rgb(40,40,55);
      color: rgb(220,220,220);
      font-size: 11px;
      padding-left: 4px;
      border-bottom: 1px solid rgb(50,50,65);
      border-radius: 4px;
    ]])
    opt:echo(val)
    opt:setClickCallback(function()
      dropdown:echo(val)
      self:close_open_dropdown()
      if cfg.on_change then cfg.on_change(dropdown.message) end
      self:refresh()
    end)
  end

  local function toggle_open()
    if self.open_dropdown == dropdown then
      self:close_open_dropdown()
    else
      self:close_open_dropdown()
      self.open_dropdown = dropdown
      dropdown.list:show()
      self.click_catcher:show()
      self.click_catcher:raiseAll()
      dropdown.list:raiseAll()
    end
  end

  dropdown:setClickCallback(toggle_open)
  dropdown.caret:setClickCallback(toggle_open)

  return dropdown
end

function RentViewer:close_open_dropdown()
  if self.open_dropdown then
    self.open_dropdown.list:hide()
    self.open_dropdown = nil
  end
  self.click_catcher:hide()
end

-- ============================================================
-- LOCATION DROPDOWN REBUILD
-- ============================================================
function RentViewer:rebuild_location_dropdown(name)
  if self.select_location then
    self.select_location:delete()
    self.select_location = nil
  end

  self.select_location = self:create_dropdown({
    name    = "RentViewer.select_location",
    parent  = self.window,
    x       = self.locationDropdownX,
    y       = self.locationDropdownY,
    width   = self.locationDropdownW,
    height  = self.locationDropdownH,
    options = self:get_zones_for_name(name),
  })
end

-- ============================================================
-- RESET FILTERS
-- ============================================================
function RentViewer:reset()
  self.input_all:print("")
  self.select_name:echo("All")
  self:rebuild_location_dropdown("All")
  self.input_item:print("")
  self.search_rare = false
  self:update_button_rare()
  self.search_angreal = false
  self:update_button_angreal()
  self.is_summary = false
  self:update_button_summary()
  self.sort_by = "name"
  self.sort_ascending = true
end

-- ============================================================
-- UI CONSTRUCTION
-- ============================================================
function RentViewer:buildUI()
  if self.window then
    self.window:delete()
    self.window = nil
  end

  self.open_dropdown = nil

  local startX, startY = getCenteredCoordinates()

  self.window = Adjustable.Container:new({
    name = self.windowName,
    x = startX, y = startY,
    width = self.width, height = self.height,
    titleText = "Rents",
    adjLabelstyle = [[
      background-color: rgb(15,15,20); 
      border: 2px solid rgb(90,90,110); 
      border-radius: 4px;
    ]],
    buttonstyle = [[
      QLabel {
        border-radius: 4px;
        background-color: rgba(140,140,140,100%);
      }
      QLabel::hover {
        background-color: rgba(160,160,160,50%);
      }
    ]],
    autoSave = false,
    autoLoad = false,
    hidden = true
  })

  self.window:resize(self.width, self.height)
  self.window:move(startX, startY)

  function self.window:hide(...)
    Adjustable.Container.hide(self, ...)
    RentViewer:hide()
  end

  -- Click-catcher: dismisses open dropdowns on outside clicks
  self.click_catcher = Geyser.Label:new({
    name = "RentViewer.click_catcher",
    x = 0, y = 0, width = "100%", height = "100%",
  }, self.window)
  self.click_catcher:setStyleSheet("background-color: rgba(0,0,0,0);")
  self.click_catcher:setClickCallback(function() self:close_open_dropdown() end)
  self.click_catcher:hide()

  self:build_filters()
  self:build_display()
end

function RentViewer:build_filters()
  local lblH    = 14
  local inputH  = 26
  local lblGap  = 2
  local filterY = 20
  local colGap  = 8
  local curX    = 5

  local labelY = filterY
  local inputY = filterY + lblH + lblGap

  local lbl_style   = [[
    color: rgb(160,160,180);
    font-size: 10px;
    background: transparent;
    padding: 0px;
    font-size: 10px;
  ]]
  local input_style = [[
    background-color: rgb(30,30,40);
    border: 1px solid rgb(90,90,110);
    border-radius: 4px;
    font-size: 14px;
    padding: 2px 4px;
  ]]
  local omniW    = 175
  local nameW    = 225
  local locW     = 225
  local itemW    = 175
  local rareW    = 55
  local angrealW = 75
  local summaryW = 85
  local clearW   = 65

  --Search All
  local label_all = Geyser.Label:new({
    name = "RentViewer.label_all", x = curX, y = labelY, width = omniW, height = lblH,
  }, self.window)
  label_all:setStyleSheet(lbl_style)
  label_all:echo("Search All")

  self.input_all = Geyser.CommandLine:new({
    name = "RentViewer.input_all", x = curX, y = inputY, width = omniW, height = inputH,
  }, self.window)
  self.input_all:setStyleSheet(input_style)
  self.input_all:setAction(function() end)
  curX = curX + omniW + colGap

  --Name
  local label_name = Geyser.Label:new({
    name = "RentViewer.label_name", x = curX, y = labelY, width = nameW, height = lblH,
  }, self.window)
  label_name:setStyleSheet(lbl_style)
  label_name:echo("Character")

  self.select_name = self:create_dropdown({
    name    = "RentViewer.select_name",
    parent  = self.window,
    x = curX, y = inputY, width = nameW, height = inputH,
    options = self:get_unique_values("name"),
    on_change = function(selectedName)
      self:rebuild_location_dropdown(selectedName)
    end,
  })
  curX = curX + nameW + colGap

  --Location
  local label_location = Geyser.Label:new({
    name = "RentViewer.label_location", x = curX, y = labelY, width = locW, height = lblH,
  }, self.window)
  label_location:setStyleSheet(lbl_style)
  label_location:echo("Location")

  self.locationDropdownX = curX
  self.locationDropdownY = inputY
  self.locationDropdownW = locW
  self.locationDropdownH = inputH

  self.select_location = self:create_dropdown({
    name    = "RentViewer.select_location",
    parent  = self.window,
    x = curX, y = inputY, width = locW, height = inputH,
    options = self:get_unique_values("zone"),
  })
  curX = curX + locW + colGap

  --Item
  local label_item = Geyser.Label:new({
    name = "RentViewer.label_item", x = curX, y = labelY, width = itemW, height = lblH,
  }, self.window)
  label_item:setStyleSheet(lbl_style)
  label_item:echo("Item")

  self.input_item = Geyser.CommandLine:new({
    name = "RentViewer.input_item", x = curX, y = inputY, width = itemW, height = inputH,
  }, self.window)
  self.input_item:setStyleSheet(input_style)
  self.input_item:setAction(function() end)
  curX = curX + itemW + colGap

  --Rare checkbox
  self.search_rare = false
  self.button_rare = Geyser.Label:new({
    name = "RentViewer.button_rare", x = curX, y = inputY, width = rareW, height = inputH,
  }, self.window)
  self:update_button_rare()
  self.button_rare:setClickCallback(function()
    self.search_rare = not self.search_rare
    if self.search_rare then
      self.search_angreal = false
      self:update_button_angreal()
    end
    self:update_button_rare()
    self:refresh()
  end)
  curX = curX + rareW + colGap

  --Angreal checkbox
  self.search_angreal = false
  self.button_angreal = Geyser.Label:new({
    name = "RentViewer.button_angreal", x = curX, y = inputY, width = angrealW, height = inputH,
  }, self.window)
  self:update_button_angreal()
  self.button_angreal:setClickCallback(function()
    self.search_angreal = not self.search_angreal
    if self.search_angreal then
      self.search_rare = false
      self:update_button_rare()
    end
    self:update_button_angreal()
    self:refresh()
  end)
  curX = curX + angrealW + colGap

  --Summary toggle
  self.is_summary = false
  self.button_summary = Geyser.Label:new({
    name = "RentViewer.button_summary", x = -clearW - summaryW - colGap - 5, y = inputY, width = summaryW, height = inputH,
  }, self.window)
  self:update_button_summary()
  self.button_summary:setClickCallback(function()
    self.is_summary = not self.is_summary
    self:update_button_summary()
    self:refresh()
  end)

  --Reset button
  local button_refresh = Geyser.Label:new({
    name = "RentViewer.button_refresh", x = -clearW - 5, y = inputY, width = clearW, height = inputH,
  }, self.window)
  button_refresh:setStyleSheet([[
    background-color: rgb(80,60,30);
    border: 1px solid rgb(140,110,60);
    color: white; font-weight: bold; font-size: 11px; border-radius: 4px;
  ]])
  button_refresh:echo("Reset")
  button_refresh:setAlignment("center")
  button_refresh:setClickCallback(function()
    self:reset()
    self:refresh()
  end)
end

function RentViewer:update_button_rare()
  if self.search_rare then
    self.button_rare:setStyleSheet([[
      background-color: rgb(40,80,40);
      border: 1px solid rgb(80,160,80);
      color: rgb(120,255,120);
      font-size: 11px;
      font-weight: bold;
      border-radius: 4px;
    ]])
    self.button_rare:echo("☑ Rare")
  else
    self.button_rare:setStyleSheet([[
      background-color: rgb(30,30,40);
      border: 1px solid rgb(90,90,110);
      color: rgb(180,180,180);
      font-size: 11px;
      border-radius: 4px;
    ]])
    self.button_rare:echo("☐ Rare")
  end
  self.button_rare:setAlignment("center")
end

function RentViewer:update_button_angreal()
  if self.search_angreal then
    self.button_angreal:setStyleSheet([[
      background-color: rgb(50,40,80);
      border: 1px solid rgb(120,80,200);
      color: rgb(190,140,255);
      font-size: 11px;
      font-weight: bold;
      border-radius: 4px;
    ]])
    self.button_angreal:echo("☑ Angreal")
  else
    self.button_angreal:setStyleSheet([[
      background-color: rgb(30,30,40);
      border: 1px solid rgb(90,90,110);
      color: rgb(180,180,180);
      font-size: 11px;
      border-radius: 4px;
    ]])
    self.button_angreal:echo("☐ Angreal")
  end
  self.button_angreal:setAlignment("center")
end

function RentViewer:update_button_summary()
  if self.is_summary then
    self.button_summary:setStyleSheet([[
      background-color: rgb(40,55,75);
      border: 1px solid rgb(80,140,210);
      color: rgb(130,185,255);
      font-size: 11px;
      font-weight: bold;
      border-radius: 4px;
    ]])
    self.button_summary:echo("☑ Summary")
  else
    self.button_summary:setStyleSheet([[
      background-color: rgb(30,30,40);
      border: 1px solid rgb(90,90,110);
      color: rgb(180,180,180);
      font-size: 11px;
      border-radius: 4px;
    ]])
    self.button_summary:echo("☐ Summary")
  end
  self.button_summary:setAlignment("center")
end

function RentViewer:build_display()
  local filterY  = 20
  local filterH  = 42
  local tableTop = filterY + filterH + 12
  local headerH  = 25
  local countH   = 16

  self.display_container = Geyser.Container:new({
    name = "RentViewer.display_container",
    x = 5, y = tableTop, width = "-5px",
    height = "-" .. (countH + 4) .. "px",
  }, self.window)

  self.header_container = Geyser.Container:new({
    name = "RentViewer.header_container",
    x = 0, y = 0, width = "100%", height = headerH,
  }, self.display_container)

  self.console = Geyser.MiniConsole:new({
    name = "RentViewer.console",
    x = 0, y = headerH + 2, width = "100%", height = "-5px",
  }, self.display_container)
  self.console:setColor("black")
  self.console:setFont("Courier New")
  self.console:setFontSize(10)
  self.console:enableScrolling()
  self.console:enableScrollBar()

  self.label_count = Geyser.Label:new({
    name = "RentViewer.label_count",
    x = -305, y = "-" .. (countH + 1) .. "px",
    width = 300, height = countH,
  }, self.window)
  self.label_count:setStyleSheet("background-color: transparent; color: rgb(180,180,180); font-size: 11px;")

  self:build_column_headers()
end

function RentViewer:build_column_headers()
  local charW = calcFontSize(10, "Courier New")
  if not charW or charW <= 0 then charW = 8 end

  local CONSOLE_INDENT_PX = charW - 3

  local columns = {
    {field = "name",     label = "Character", widthChars = COLUMN_WIDTHS.name },
    {field = "location", label = "Location",  widthChars = COLUMN_WIDTHS.location },
    {field = "item",     label = "Item",      widthChars = COLUMN_WIDTHS.item },
    {field = "cost",     label = "Amount",    widthChars = COLUMN_WIDTHS.cost },
  }

  self.headers = {}
  local charOffset = 0

  for i, col in ipairs(columns) do
    local labelX     = (i == 1) and 0 or (CONSOLE_INDENT_PX + charOffset * charW)
    local labelWidth

    if i < #columns then
      local nextColX = CONSOLE_INDENT_PX + (charOffset + col.widthChars + COLUMN_GAP) * charW
      labelWidth     = nextColX - labelX - 3
    else
      labelWidth = self.header_container:get_width() - labelX
    end

    local lbl = Geyser.Label:new({
      name = f'RentViewer.header.{col.field}',
      x = labelX, y = 0, width = labelWidth, height = "100%",
    }, self.header_container)

    lbl:setClickCallback(function()
      if self.sort_by == col.field then
        self.sort_ascending = not self.sort_ascending
      else
        self.sort_by = col.field
        self.sort_ascending = true
      end
      self:refresh()
    end)

    self.headers[col.field] = {
      widget = lbl,
      label  = col.label,
      indent = (i == 1) and CONSOLE_INDENT_PX or 0,
    }

    charOffset = charOffset + col.widthChars + COLUMN_GAP
  end
end

function RentViewer:start_live_timer()
  self.lastItemText = self.input_item:getText()
  self.lastOmniText = self.input_all:getText()
  if self.liveTimer then killTimer(self.liveTimer) end
  self.liveTimer = tempTimer(0.3, function()
    if not self.window then return end
    local okItem, itemText = pcall(function() return self.input_item:getText() end)
    local okOmni, omniText = pcall(function() return self.input_all:getText() end)
    itemText = okItem and itemText or self.lastItemText
    omniText = okOmni and omniText or self.lastOmniText
    if itemText ~= self.lastItemText or omniText ~= self.lastOmniText then
      self.lastItemText = itemText
      self.lastOmniText = omniText
      self:refresh()
    end

    if self.window.width ~= self.width .. "px" then
      --cecho(self.window.width)

      --cecho(self.window.width.. " " .. self.window.height .."\n")
      --self.window:resize(self.width, self.window.height)
      --cecho("resized")
    end
  end, true)
end

-- ============================================================
-- RENDERING HELPERS
-- ============================================================
local function buildHighlightedText(text, width, matchTerm, textColor, highlightColor, bg)
  local fitted = rents:fit_to_width(text, width)

  local function tag(fg, background)
    return string.format("<%d,%d,%d:%d,%d,%d>", fg[1], fg[2], fg[3], background[1], background[2], background[3])
  end

  if matchTerm and matchTerm ~= "" then
    local lowerFitted      = fitted:lower()
    local lowerTerm        = matchTerm:lower()
    local startIdx, endIdx = lowerFitted:find(lowerTerm, 1, true)
    if startIdx then
      local s = ""
      if startIdx > 1 then
        s = s .. tag(textColor, bg) .. fitted:sub(1, startIdx - 1)
      end
      s = s .. tag(highlightColor, bg) .. fitted:sub(startIdx, endIdx)
      if endIdx < #fitted then
        s = s .. tag(textColor, bg) .. fitted:sub(endIdx + 1)
      end
      return s
    end
  end
  return tag(textColor, bg) .. fitted
end

local function renderHighlightedCell(console, text, width, matchTerm, textColor, highlightColor, bg)
  console:decho(buildHighlightedText(text, width, matchTerm, textColor, highlightColor, bg))
end

local function renderHighlightedLink(console, text, width, matchTerm, textColor, highlightColor, bg, command, hint)
  console:dechoLink(buildHighlightedText(text, width, matchTerm, textColor, highlightColor, bg), command, hint, true)
end

local function renderHighlightedPopup(console, text, width, matchTerm, textColor, highlightColor, bg, actions, hints)
  console:dechoPopup(buildHighlightedText(text, width, matchTerm, textColor, highlightColor, bg), actions, hints, true)
end

local function renderHeaders(self)
  local style = [[
    background-color: rgb(45, 45, 60);
    border-bottom: 2px solid rgb(90, 90, 115);
    color: %s;
    font-family: 'Courier New';
    font-size: 11px;
    font-weight: %s;
    padding-left: %dpx;
  ]]

  for field, header in pairs(self.headers) do
    local is_active = (self.sort_by == field)
    local color    = is_active and "rgb(255, 215, 0)" or "rgb(185, 185, 185)"
    local weight   = is_active and "bold" or "normal"

    local text
    if self.is_summary and field == "item" then
      text = "Item Count"
    elseif self.is_summary and field == "cost" then
      text = "Sum Amount"
    else
      text = header.label
    end

    text = text .. (is_active and (self.sort_ascending and " ▲" or " ▼") or "")

    header.widget:setStyleSheet(style:format(color, weight, header.indent))
    header.widget:echo(text)
  end
end

-- ============================================================
-- FILTER + REFRESH
-- ============================================================
function RentViewer:get_active_filters()
  return {
    omni     = self.input_all:getText():lower(),
    item     = self.input_item:getText():lower(),
    location = self.select_location.message:lower(),
    name     = self.select_name.message:lower(),
    search_rare = self.search_rare,
    search_angreal = self.search_angreal,
  }
end

function RentViewer:filter_records(filters)
  local records = {}

  for _, rec in ipairs(self.records) do
    local name = rec.name:lower()
    local zone = rec.zone:lower()
    local location = rec.location:lower()
    local item = rec.item:lower()

    local match_all = (filters.omni == "")
      or item:find(filters.omni, 1, true)
      or name:find(filters.omni, 1, true)
      or location:find(filters.omni, 1, true)

    local match_item = (filters.item == "") or item:find(filters.item, 1, true)
    local match_location = (filters.location == "all") or (zone == filters.location)
    local match_name = (filters.name == "all") or (name == filters.name)

    local match_rare = true
    if filters.search_rare then
      match_rare = false
      for _, rare in ipairs(rents.rares) do
        if item:find(rare:lower(), 1, true) then
          match_rare = true
          break
        end
      end
    end

    local match_angreal = true
    if filters.search_angreal then
      match_angreal = false
      for _, angreal in ipairs(rents.angreal) do
        if item:find(angreal:lower(), 1, true) then
          match_angreal = true
          break
        end
      end
    end

    if match_all and match_item and match_location and match_name and match_rare and match_angreal then
      table.insert(records, rec)
    end
  end

  return records
end

function RentViewer:sort_records(records)
  local sort_by = self.sort_by
  local ascending = self.sort_ascending

  table.sort(records, function(a, b)
    local function cmp_asc(valA, valB, fallback)
      if valA ~= valB then return valA < valB end
      return fallback()
    end

    local function cmp_primary(valA, valB, fallback)
      if valA ~= valB then
        if ascending then return valA < valB else return valA > valB end
      end
      return fallback()
    end

    local name = function(x) return x.name:lower() end
    local loc  = function(x) return x.location:lower() end
    local item = function(x) return x.item:lower() end
    local cost = function(x) return x.coppers end

    if sort_by == "name" then
      return cmp_primary(name(a), name(b), function()
        return cmp_asc(loc(a), loc(b), function()
          return cmp_asc(item(a), item(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    elseif sort_by == "location" then
      return cmp_primary(loc(a), loc(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(item(a), item(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    elseif sort_by == "item" then
      return cmp_primary(item(a), item(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(loc(a), loc(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    else -- cost
      return cmp_primary(cost(a), cost(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(loc(a), loc(b), function()
            return item(a) < item(b)
          end)
        end)
      end)
    end
  end)
end

function RentViewer:sortSummaryGroups(groups)
  local sort_by = self.sort_by
  local ascending = self.sort_ascending

  table.sort(groups, function(a, b)
    local function cmp_asc(valA, valB, fallback)
      if valA ~= valB then return valA < valB end
      return fallback()
    end

    local function cmp_primary(valA, valB, fallback)
      if valA ~= valB then
        if ascending then return valA < valB else return valA > valB end
      end
      return fallback()
    end

    local name = function(x) return x.name:lower() end
    local loc  = function(x) return x.location:lower() end
    local item = function(x) return x.count end
    local cost = function(x) return x.totalCost end

    if sort_by == "name" then
      return cmp_primary(name(a), name(b), function()
        return cmp_asc(loc(a), loc(b), function()
          return cmp_asc(item(a), item(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    elseif sort_by == "location" then
      return cmp_primary(loc(a), loc(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(item(a), item(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    elseif sort_by == "item" then
      return cmp_primary(item(a), item(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(loc(a), loc(b), function()
            return cost(a) < cost(b)
          end)
        end)
      end)
    else -- cost
      return cmp_primary(cost(a), cost(b), function()
        return cmp_asc(name(a), name(b), function()
          return cmp_asc(loc(a), loc(b), function()
            return item(a) < item(b)
          end)
        end)
      end)
    end
  end)
end

function RentViewer:refresh()
  renderHeaders(self)

  local filters = self:get_active_filters()
  local records = self:filter_records(filters)

  local console        = self.console
  local textColor      = self.textColor
  local highlightColor = self.highlightColor
  local gapStr         = string.rep(" ", COLUMN_GAP)
  console:clear()

  local function activeMatchFor(colText, specificFilter)
    if specificFilter ~= "" then return specificFilter end
    if filters.omni ~= "" and colText:lower():find(filters.omni, 1, true) then
      return filters.omni
    end
    return ""
  end

  --Summary mode
  if self.is_summary then
    local groups   = {}
    local keyOrder = {}

    for _, rec in ipairs(records) do
      local key = rec.name .. "\0" .. rec.location
      if not groups[key] then
        groups[key] = {
          name      = rec.name,
          location  = rec.location,
          room      = rec.room,
          count     = 0,
          totalCost = 0,
          isBank    = (rec.location == "*Bank"),
          items     = {},
        }
        table.insert(keyOrder, key)
      end
      if not groups[key].isBank then
        groups[key].count = groups[key].count + 1
        table.insert(groups[key].items, { name = rec.item, coppers = rec.coppers })
      end
      groups[key].totalCost = groups[key].totalCost + rec.coppers
    end

    local sorted = {}
    for _, k in ipairs(keyOrder) do
      table.insert(sorted, groups[k])
    end

    self:sortSummaryGroups(sorted)

    local rowToggle = false
    for _, grp in ipairs(sorted) do
      rowToggle = not rowToggle
      local bg  = rowToggle and self.oddRowColor or self.evenRowColor

      local function cell(text, width, matchTerm)
        renderHighlightedCell(console, text, width, matchTerm, textColor, highlightColor, bg)
      end
      local function link(text, width, matchTerm, command, hint)
        renderHighlightedLink(console, text, width, matchTerm, textColor, highlightColor, bg, command, hint)
      end
      local function popup(text, width, matchTerm, actions, hints)
        renderHighlightedPopup(console, text, width, matchTerm, textColor, highlightColor, bg, actions, hints)
      end
      local function gap()
        console:setBgColor(bg[1], bg[2], bg[3])
        console:echo(gapStr)
      end

      console:setBgColor(bg[1], bg[2], bg[3])
      console:echo(" ")

      cell(grp.name,     COLUMN_WIDTHS.name,     activeMatchFor(grp.name,     filters.name))      
      gap()

      if grp.room and grp.room > 0 then
        link(grp.location, COLUMN_WIDTHS.location, activeMatchFor(grp.location, filters.location), function() centerview(grp.room) end, "Click to center map on room.")
      else
        cell(grp.location, COLUMN_WIDTHS.location, activeMatchFor(grp.location, filters.location))
      end
      gap()

      --Item count cell
      local itemText = grp.isBank and "bank balance" or (grp.count == 1 and "1 item" or grp.count .. " items")
      if grp.isBank or #grp.items == 0 then
        cell(itemText, COLUMN_WIDTHS.item, activeMatchFor(itemText, filters.location))
      else
        local hints   = {}
        local actions = {}
        for _, itm in ipairs(grp.items) do
          local costStr    = rents:coppers_to_str(itm.coppers)
          table.insert(hints, "   " .. itm.name .. "  |  " .. costStr .. "   ")
          table.insert(actions, "")
        end
        popup(itemText, COLUMN_WIDTHS.item, "", actions, hints)
      end
      gap()

      local costStr = rents:coppers_to_str(grp.totalCost)
      cell(costStr, COLUMN_WIDTHS.cost, "")

      console:setFgColor(255, 255, 255)
      console:setBgColor(0,   0,   0)
      console:echo("\n")
      console:resetFormat()
    end

    if #sorted == 0 then
      console:setFgColor(150, 150, 150)
      console:setBgColor(0,   0,   0)
      console:echo(" No matching results.\n")
    end

    self.label_count:cecho("<p style='text-align: right'><gray>" ..
      string.format(#sorted == 1 and "%d result" or "%d results", #sorted))

    console:scrollTo(console:getLineCount())
    return
  end

  --Individual record mode (default)
  self:sort_records(records)
  local count = #records

  local rowToggle = false
  for _, rec in ipairs(records) do
    rowToggle = not rowToggle
    local bg  = rowToggle and self.oddRowColor or self.evenRowColor

    local function cell(text, width, matchTerm)
      renderHighlightedCell(console, text, width, matchTerm, textColor, highlightColor, bg)
    end
    local function link(text, width, matchTerm, command, hint)
      renderHighlightedLink(console, text, width, matchTerm, textColor, highlightColor, bg, command, hint)
    end
    local function popup(text, width, matchTerm, actions, hints)
      renderHighlightedPopup(console, text, width, matchTerm, textColor, highlightColor, bg, actions, hints)
    end
    local function gap()
      console:setBgColor(bg[1], bg[2], bg[3])
      console:echo(gapStr)
    end

    console:setBgColor(bg[1], bg[2], bg[3])
    console:echo(" ")

    cell(rec.name,     COLUMN_WIDTHS.name,     activeMatchFor(rec.name,     filters.name))
    gap()

    if rec.room and rec.room > 0 then
      link(rec.location, COLUMN_WIDTHS.location, activeMatchFor(rec.location, filters.location), function() centerview(rec.room) end, "Click to center map on room.")
    else
      cell(rec.location, COLUMN_WIDTHS.location, activeMatchFor(rec.location, filters.location))
    end
    gap()

    cell(rec.item,     COLUMN_WIDTHS.item,     activeMatchFor(rec.item,     filters.item))
    gap()

    local costStr = rents:coppers_to_str(rec.coppers)
    cell(costStr, COLUMN_WIDTHS.cost, "")

    console:setFgColor(255, 255, 255)
    console:setBgColor(0,   0,   0)
    console:echo("\n")
    console:resetFormat()
  end

  if count == 0 then
    console:setFgColor(150, 150, 150)
    console:setBgColor(0,   0,   0)
    console:echo(" No matching results.\n")
  end

  self.label_count:cecho("<p style='text-align: right'><gray>" ..
    string.format(count == 1 and "%d result" or "%d results", count))    

  console:scrollTo(console:getLineCount())
end

-- ============================================================
-- SHOW / HIDE
-- ============================================================
function RentViewer:show()
  self.records = self:fetch_records()

  if not self.window then
    self:buildUI()
  end

  self:close_open_dropdown()
  self:reset()
  self:refresh()
  self:start_live_timer()

  local cx, cy = getCenteredCoordinates()
  self.window:move(cx, cy)
  self.window:show()
end

function RentViewer:hide()
  self.records = nil
  if self.liveTimer then
    killTimer(self.liveTimer)
    self.liveTimer = nil
  end
end

function RentViewer:rebuild()
  self.window:delete()
  self.window = nil
  self:show()
end
